#include <stdio.h>
#include <stdlib.h>

int main() {
    int N; scanf("%d", &N);
    // allocate arrays sized by max possible node value (100000) + 1
    static int left[100005];
    static int right[100005];
    static char isChild[100005];
    for (int i = 0; i <= 100000; ++i) { left[i]=right[i]=0; isChild[i]=0; }
    int maxNode = 0;
    for (int i = 0; i < N-1; ++i) {
        int p, c; char dir;
        scanf("%d %d %c", &p, &c, &dir);
        if (dir == 'L') left[p] = c; else right[p] = c;
        isChild[c] = 1;
        if (p > maxNode) maxNode = p;
        if (c > maxNode) maxNode = c;
    }
    int root = 1; // default when N==1
    if (N > 1) {
        for (int i = 1; i <= maxNode; ++i) {
            if ((left[i] || right[i] || isChild[i]) && !isChild[i]) { root = i; break; }
        }
    }
    // iterative preorder using manual stack
    int stack[100005];
    int top = -1;
    stack[++top] = root;
    while (top >= 0) {
        int node = stack[top--];
        printf("%d ", node);
        if (right[node]) stack[++top] = right[node];
        if (left[node])  stack[++top] = left[node];
    }
    printf("\n");
    return 0;
}

