import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int N = fs.nextInt();
        StringBuilder out = new StringBuilder();
        Map<Integer, Integer> left = new HashMap<>();
        Map<Integer, Integer> right = new HashMap<>();
        Set<Integer> child = new HashSet<>();
        Set<Integer> nodes = new HashSet<>();
        for (int i = 0; i < N - 1; i++) {
            int p = fs.nextInt();
            int c = fs.nextInt();
            char dir = fs.next().charAt(0);
            if (dir == 'L') left.put(p, c);
            else right.put(p, c);
            child.add(c);
            nodes.add(p);
            nodes.add(c);
        }
        int root;
        if (N == 1) {
            root = nodes.isEmpty() ? 1 : nodes.iterator().next();
        } else {
            root = 0;
            for (int v : nodes) if (!child.contains(v)) { root = v; break; }
        }
        Deque<Integer> stack = new ArrayDeque<>();
        stack.push(root);
        while (!stack.isEmpty()) {
            int node = stack.pop();
            out.append(node).append(' ');
            if (right.containsKey(node)) stack.push(right.get(node));
            if (left.containsKey(node))  stack.push(left.get(node));
        }
        out.append('\n');
        System.out.print(out.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return val * sign;
        }
        String next() throws IOException {
            int c;
            StringBuilder sb = new StringBuilder();
            do { c = readByte(); } while (c <= ' ');
            while (c > ' ') { sb.append((char)c); c = readByte(); }
            return sb.toString();
        }
    }
}

