import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    left = {}
    right = {}
    child = set()
    nodes = set()
    for _ in range(N-1):
        p = int(next(it)); c = int(next(it)); dir = next(it)
        if dir == 'L':
            left[p] = c
        else:
            right[p] = c
        child.add(c)
        nodes.add(p); nodes.add(c)
    if N == 1:
        root = next(iter(nodes)) if nodes else 1
    else:
        root = next(v for v in nodes if v not in child)
    stack = [root]
    res = []
    while stack:
        node = stack.pop()
        res.append(str(node))
        if node in right:
            stack.append(right[node])
        if node in left:
            stack.append(left[node])
    sys.stdout.write(' '.join(res)+'\n')

if __name__ == "__main__":
    solve()

